# Detect Article 9 categories before transfer decision

SENSITIVE_PATTERNS = {
    "health": ["diagnosis", "medication", "medical history", "patient"],
    "biometric": ["face embedding", "voice print", "fingerprint"],
    "genetic": ["genomic", "DNA sequence", "allele"],
    "criminal": ["criminal record", "conviction", "offence", "arrest record"],
}

def detect_article9(text: str) -> list[str]:
    text_lower = text.lower()
    found = []
    for category, patterns in SENSITIVE_PATTERNS.items():
        if any(p in text_lower for p in patterns):
            found.append(category)
    return found

def pre_transfer_check(prompt: str, origin_jur: str, target_jur: str):
    cats = detect_article9(prompt)
    if "criminal" in cats:
        raise PermissionError("Criminal record data cannot be processed via Claude API under Art. 10 GDPR")
    if cats and origin_jur == "EU" and target_jur != "EU":
        # Require explicit consent record before allowing transfer
        if not consent_on_file(user_id, categories=cats):
            raise PermissionError(f"Article 9 data ({cats}) requires explicit consent for EU→{target_jur} transfer")
